import React, { useEffect, useRef, useState } from 'react';
import { Chessboard } from 'react-chessboard';
import { Chess } from 'chess.js';
import { io } from 'socket.io-client';

const SOCKET_URL = 'http://localhost:3000';

export default function ChessBoard({ roomId, currentPlayer = null, boardOrientation = 'white' }) {
  const gameRef = useRef(new Chess());
  const socketRef = useRef(null);
  const [position, setPosition] = useState(gameRef.current.fen());
  const [moveHistory, setMoveHistory] = useState([]);
  const [status, setStatus] = useState('Waiting for game');

  useEffect(() => {
    if (!roomId) {
      setStatus('No room joined');
      return;
    }

    const socket = io(SOCKET_URL, { transports: ['websocket'] });
    socketRef.current = socket;

    socket.on('connect', () => {
      setStatus('Connected to server');
      socket.emit('joinRoom', { roomId });
    });

    socket.on('disconnect', () => {
      setStatus('Disconnected from server');
    });

    socket.on('roomJoined', (data) => {
      setStatus(`Joined room ${roomId}`);
      if (data.fen) {
        gameRef.current.load(data.fen);
        setPosition(data.fen);
      }
    });

    socket.on('move', (data) => {
      if (!data || !data.from || !data.to) return;
      // Ignore move from this socket itself (already applied locally)
      if (data.socketId && data.socketId === socket.id) return;

      const game = gameRef.current;
      const applied = game.move({ from: data.from, to: data.to, promotion: data.promotion || 'q' });
      if (applied) {
        setPosition(game.fen());
        setMoveHistory(prev => [...prev, `${data.from}-${data.to}`]);
        setStatus(`Opponent moved ${data.from} → ${data.to}`);
      }
    });

    socket.on('error', (err) => {
      setStatus(`Socket error: ${err?.message || err}`);
    });

    return () => {
      socket.disconnect();
      socketRef.current = null;
      setStatus('Disconnected');
    };
  }, [roomId]);

  const canMakeMove = () => {
    if (!roomId) return false;
    if (!currentPlayer) return false;
    const turn = gameRef.current.turn();
    return (turn === 'w' && currentPlayer.color === 'white') || (turn === 'b' && currentPlayer.color === 'black');
  };

  const onDrop = (sourceSquare, targetSquare) => {
    const game = gameRef.current;
    const move = game.move({ from: sourceSquare, to: targetSquare, promotion: 'q' });
    if (move === null) return false;

    setPosition(game.fen());
    setMoveHistory(prev => [...prev, move.san]);
    setStatus(`You played ${move.san}`);

    if (socketRef.current && socketRef.current.connected) {
      socketRef.current.emit('move', {
        roomId,
        from: sourceSquare,
        to: targetSquare,
        promotion: 'q',
        socketId: socketRef.current.id,
      });
    }

    return true;
  };

  return (
    <div className="w-full max-w-xl mx-auto">
      <div className="mb-3 text-sm text-slate-200">Room: {roomId || 'none'} | Status: {status}</div>
      <Chessboard
        position={position}
        onPieceDrop={onDrop}
        boardOrientation={boardOrientation}
        boardWidth={480}
        customBoardStyle={{ borderRadius: '8px', boxShadow: '0 10px 20px rgba(0,0,0,0.35)' }}
        arePiecesDraggable={canMakeMove()}
      />
      <div className="mt-4 bg-slate-800 p-3 rounded-lg text-sm text-slate-200">
        <div className="font-semibold mb-2">Move History</div>
        {moveHistory.length === 0 ? (
          <p className="text-slate-400">No moves yet</p>
        ) : (
          <ol className="list-decimal list-inside space-y-1">
            {moveHistory.map((move, idx) => (
              <li key={idx}>{move}</li>
            ))}
          </ol>
        )}
      </div>
    </div>
  );
}
